```python
# Create a new file: piece.py

class Piece:
    def __init__(self, color):
        self.color = color

    def is_king(self):
        return False

    def get_moves(self, board, position):
        # Get valid moves for a regular piece
        moves = []
        x, y = ord(position[0]) - ord('a'), int(position[1]) - 1
        if self.color == 'B':
            if y < 7 and x > 0 and board.board[y + 1][x - 1] == ' ':
                moves.append(f"{chr(x - 97 + 1)}{y + 2}")
            if y < 7 and x < 7 and board.board[y + 1][x + 1] == ' ':
                moves.append(f"{chr(x - 97 + 2)}{y + 2}")
        elif self.color == 'R':
            if y > 0 and x > 0 and board.board[y - 1][x - 1] == ' ':
                moves.append(f"{chr(x - 97 + 1)}{y}")
            if y > 0 and x < 7 and board.board[y - 1][x + 1] == ' ':
                moves.append(f"{chr(x - 97 + 2)}{y}")
        return moves

class King(Piece):
    def __init__(self, color):
        super().__init__(color)

    def is_king(self):
        return True

    def get_moves(self, board, position):
        # Get valid moves for a king
        moves = []
        x, y = ord(position[0]) - ord('a'), int(position[1]) - 1
        directions = [(1, 1), (1, -1), (-1, 1), (-1, -1)]
        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            while 0 <= nx < 8 and 0 <= ny < 8:
                if board.board[ny][nx] == ' ':
                    moves.append(f"{chr(nx + ord('a'))}{ny + 1}")
                elif board.board[ny][nx].color != self.color:
                    moves.append(f"{chr(nx + ord('a'))}{ny + 1}")
                    break
                nx += dx
                ny += dy
        return moves

