# Create a new file: game.py

from board import Board
from piece import Piece, King

class CheckersGame:
    def __init__(self):
        self.board = Board()
        self.current_player = 'B'

    def switch_player(self):
        # Switch current player
        if self.current_player == 'B':
            self.current_player = 'R'
        else:
            self.current_player = 'B'

    def is_game_over(self):
        # Check if the game is over (either side has no pieces left)
        pieces = []
        for row in self.board.board:
            for piece in row:
                if isinstance(piece, Piece) and piece.color == self.current_player:
                    pieces.append(piece)
        return len(pieces) == 0

    def make_move(self, start_pos, end_pos):
        # Make a move and switch players
        current_piece = self.get_piece(start_pos)
        if isinstance(current_piece, Piece):
            moves = current_piece.get_moves(self.board, start_pos)
            if end_pos in moves:
                self.board.move_piece(start_pos, end_pos)
                if isinstance(current_piece, Piece) and end_pos[1] == '8' if self.current_player == 'B' else end_pos[1] == '1':
                    current_piece = King(self.current_player)
                    self.board.set_piece(end_pos, current_piece)
                self.switch_player()
            else:
                raise ValueError("Invalid move")
        else:
            raise ValueError("No piece at start position")

    def get_piece(self, position):
        # Get piece at a specific position
        return self.board.get_piece(position)

