class Board:
    def __init__(self):
        self.board = [[' ' if (i + j) % 2 else 'w' if i < 3 else 'b' for j in range(8)] for i in range(8)]
        self.turn = 'w'

    def print_board(self):
        for row in self.board:
            print(' '.join(row))

    def move_piece(self, from_pos, to_pos):
        x1, y1 = from_pos
        x2, y2 = to_pos
        if self.board[x1][y1] == self.turn and (abs(x1 - x2) == 2 and abs(y1 - y2) == 2):
            self.board[x2][y2] = self.board[x1][y1]
            self.board[x1][y1] = ' '
            if (self.turn == 'w' and x2 == 0) or (self.turn == 'b' and x2 == 7):
                self.board[x2][y2] = self.turn.upper()
            self.turn = 'b' if self.turn == 'w' else 'w'

class Game:
    def __init__(self):
        self.board = Board()

    def start(self):
        while True:
            self.board.print_board()
            move_from = input("Enter the position of the piece to move (e.g., 01): ")
            move_to = input("Enter the target position for the piece (e.g., 23): ")
            move_from = (int(move_from[0]), int(move_from[1]))
            move_to = (int(move_to[0]), int(move_to[1]))
            self.board.move_piece(move_from, move_to)

if __name__ == "__main__":
    game = Game()
    game.start()
